import{_ as t,c as i,a as r,o as s}from"./app-CEcM0piI.js";const o={};function n(p,e){return s(),i("div",null,e[0]||(e[0]=[r('<p><strong>⌚️投递时间：5.20</strong></p><p><strong>👋一面：5.21</strong></p><p><strong>🤏二面：5.23</strong></p><p><strong>二面挂</strong></p><p><strong>一面（5.21）：</strong></p><p>飞书视频会议，无人面试，自己录屏后发送链接给一面hr</p><p>四道逻辑思维题，答出来两道。</p><p>一道算法题，从力扣37题改的，比37要难是无规则的数独。没写出来</p><p>八股：</p><ol><li>简述Vue.js的生命周期函数及其执行顺序。</li><li>Vue.js中的v-bind指令和v-model指令有什么区别?</li><li>简述Vue.js的组件通信方式及其优缺点。</li><li>Vue.js如何实现父子组件之间的数据传递?</li><li>简述Vue.js中的响应式原理。</li><li>如何在Vue.js中实现路由跳转?</li><li>Vue.js中的computed和watch有什么区别?</li><li>Vue.js中的v-for指令和v-if指令有什么区别?</li><li>简述Vue.js中的mixins和extends的作用及其区别。</li><li>Vue.js中的keep-alive组件有什么作用?如何使用?</li></ol><p><strong>二面（5.23）：</strong></p><p>一面结束第二天（5.22）通知通过面试，然后让加二面hr微信，加了后让录自己项目的视频并且再发一份简历给他，然后又问了点课表。鼠鼠以为已经开始面试了，第二天问结果他说还没面试。然后就约面试时间是5.23，但时间段跟我安排冲突，就请求换个时间段被二面hr拒绝。于是二面就没去。（ps：二面hr态度很差）</p><p>作者：呆虫仙尊<br> 链接：<a href="https://www.nowcoder.com/discuss/760582985367183360?sourceSSR=users" target="_blank" rel="noopener noreferrer">https://www.nowcoder.com/discuss/760582985367183360?sourceSSR=users</a><br> 来源：牛客网</p>',13)]))}const a=t(o,[["render",n]]),c=JSON.parse('{"path":"/article/20250606/","title":"智乐活前端实习面试time line","lang":"zh-CN","frontmatter":{"title":"智乐活前端实习面试time line","createTime":"2025/06/06 21:52","tags":["面经","前端"],"permalink":"/article/20250606/"},"readingTime":{"minutes":1.36,"words":407},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"面试/智乐活前端实习面试time line.md","headers":[],"categoryList":[{"id":"1573c7","sort":10000,"name":"面试"}]}');export{a as comp,c as data};
